import{_ as t,a,b as n,c as i,d as s,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o as d,c as r,a2 as c}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"IP Geolocation và User Management","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/ip-geolocation-and-user-management.md","filePath":"vi-VN/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),p={name:"vi-VN/Other/ip-geolocation-and-user-management.md"};function h(u,e,g,m,b,v){return d(),r("div",null,[...e[0]||(e[0]=[c('<h1 id="ip-geolocation-va-user-management" tabindex="-1">IP Geolocation và User Management <a class="header-anchor" href="#ip-geolocation-va-user-management" aria-label="Permalink to &quot;IP Geolocation và User Management&quot;">​</a></h1><p>IP geolocation chuyển IP addresses trong uploader records, login devices và logs tương tự thành locations gần đúng.</p><p>Sau khi cấu hình, admin panel có thể hiển thị nguồn upload và access rõ hơn. User Management cũng cho phép block hoặc restore upload access cho IP addresses đáng ngờ.</p><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Mở:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+t+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>Flow IP geolocation mới hỗ trợ nhiều sources thay vì phụ thuộc một map service.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Chọn display language, như English, Simplified Chinese, Japanese, French và các ngôn ngữ khác.</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind account ID cho MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. Hữu ích cho Chinese addresses và mainland China IPs.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. Hỗ trợ multilingual IP geolocation.</td></tr></tbody></table><p>Chỉ điền services bạn cần. Không bắt buộc cấu hình mọi field.</p><p>Nếu không cung cấp key, ImgBed vẫn thử built-in free sources, nhưng stability, language support và precision có thể thấp hơn service bạn tự cấu hình.</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>Nếu chủ yếu cần Chinese addresses:</p><ol><li>Đặt IP geolocation language là Simplified Chinese.</li><li>Cấu hình Tencent Map Key.</li><li>Có thể thêm MaxMind hoặc ipapi làm fallback sources.</li></ol><p>Nếu chủ yếu cần English hoặc multilingual addresses:</p><ol><li>Chọn language bạn cần.</li><li>Cấu hình MaxMind Account ID và License Key.</li><li>Thêm ipapi Key nếu cần multilingual results tốt hơn.</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind cần:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Tìm account ID trong MaxMind dashboard và generate License Key từ License Keys page.</p><p><img src="`+a+'" alt="MaxMind key config" loading="lazy"></p><p>Sau khi generate, paste Account ID và License Key vào ImgBed rồi save.</p><p>Free plan của MaxMind phù hợp everyday use, nhưng có request limits. Nếu quota vượt giới hạn, ImgBed tiếp tục thử sources khả dụng khác.</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi dùng APILayer API Key.</p><p>Mở ipapi console và copy API Key hiển thị ở đó.</p><p><img src="'+n+'" alt="ipapi config" loading="lazy"></p><p>Paste vào field <code>ipapi Key</code> trong ImgBed rồi save.</p><p>ipapi hỗ trợ multilingual IP geolocation và hữu ích khi muốn addresses hiển thị bằng selected language. Free plan cũng có request limits. Nếu quota hết, ImgBed tiếp tục thử sources khả dụng khác.</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key hữu ích cho Chinese addresses, đặc biệt là mainland China IPs.</p><p>Khi tạo key trong Tencent Location Service, enable:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Sau khi tạo, paste key vào <code>Tencent Map Key</code> và save.</p><p>Nếu chỉ cần basic Chinese IP geolocation, Tencent Map Key là đủ để bắt đầu.</p><h2 id="can-xem-gi-trong-user-management" tabindex="-1">Cần xem gì trong User Management <a class="header-anchor" href="#can-xem-gi-trong-user-management" aria-label="Permalink to &quot;Cần xem gì trong User Management&quot;">​</a></h2><p>User Management có thể mở từ đầu admin panel.</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management hiển thị upload activity theo IP:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>Uploader source IP.</td></tr><tr><td>Address</td><td>Location gần đúng được resolve từ IP.</td></tr><tr><td>Total upload size</td><td>Tổng file size đã upload từ IP này.</td></tr><tr><td>Upload count</td><td>Số uploads từ IP này.</td></tr><tr><td>Upload allowed</td><td>On nghĩa là uploads được phép. Off nghĩa là uploads bị block.</td></tr></tbody></table><p>Nhấn arrow bên trái để mở danh sách files đã upload bởi IP đó.</p><p>File list hiển thị file name, preview, file size, moderation result, file status và upload time. Khi uploads trông đáng ngờ, hãy expand IP trước, review files, rồi quyết định có block uploads tiếp theo không.</p><p>Nếu một IP đáng ngờ, tắt <code>Upload allowed</code>. Future uploads từ IP đó sẽ bị block.</p><h2 id="search-sort-va-advanced-filters" tabindex="-1">Search, Sort và Advanced Filters <a class="header-anchor" href="#search-sort-va-advanced-filters" aria-label="Permalink to &quot;Search, Sort và Advanced Filters&quot;">​</a></h2><p>Ở đầu User Management, search theo IP source hoặc address.</p><p>Sort theo time, upload count hoặc total upload size để tìm recent uploaders, high-frequency uploaders hoặc high-usage IPs.</p><p>Để điều tra sâu hơn, mở advanced filters.</p><p><img src="'+s+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters hỗ trợ:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>Hiển thị IPs đã upload files trong khoảng thời gian chọn.</td></tr><tr><td>Access status</td><td>Filter theo normal, blocked và states tương tự.</td></tr><tr><td>Allow/block list</td><td>Filter theo allowlist, blocklist hoặc unset.</td></tr><tr><td>File type</td><td>Hiển thị IPs đã upload images, videos, audio, documents, code hoặc other files.</td></tr><tr><td>File size</td><td>Filter theo uploaded file size range.</td></tr><tr><td>Age rating</td><td>Filter theo unset, General, R12+, R16+, R18 và ratings tương tự.</td></tr><tr><td>File status</td><td>Filter theo current file status để điều tra abnormal files.</td></tr></tbody></table><p>Nhấn <code>Apply Filters</code> để áp dụng. Dùng <code>Reset</code> để quay lại toàn bộ dữ liệu.</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>Trên mobile, User Management chuyển sang card layout.</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>Mỗi card hiển thị IP, address, total upload size, upload count và upload allowed switch. Bạn có thể manage users mà không cần scroll table ngang.</p><h2 id="neu-location-co-ve-sai" tabindex="-1">Nếu Location có vẻ sai <a class="header-anchor" href="#neu-location-co-ve-sai" aria-label="Permalink to &quot;Nếu Location có vẻ sai&quot;">​</a></h2><p>IP geolocation là gần đúng. Nó không phải street address chính xác.</p><p>Nếu user đứng sau proxy, data center, cloud server hoặc cross-border network, location hiển thị có thể khác location thật.</p><p>Dùng feature này để hiểu rough origin, tìm abnormal uploads và hỗ trợ quyết định blocking. Không nên xem nó là precise tracking.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address trống</td><td>IP có thể chưa resolve, hoặc current source temporarily unavailable.</td></tr><tr><td>Address language sai</td><td>Kiểm tra IP geolocation language và source hỗ trợ language đó đã được cấu hình chưa.</td></tr><tr><td>Address hiển thị data center</td><td>Nhiều proxies, cloud servers và crawlers xuất hiện như data center hoặc ISP addresses.</td></tr><tr><td>Upload count cao</td><td>Review IP này kỹ và block uploads nếu cần.</td></tr><tr><td>Total upload size lớn</td><td>Sort hoặc filter, expand IP rồi inspect specific files.</td></tr><tr><td>Cần restore sau khi block</td><td>Bật lại <code>Upload allowed</code>.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mở IP Geolocation trong Other Settings</span></span>
<span class="line"><span>-&gt; Chọn IP geolocation language</span></span>
<span class="line"><span>-&gt; Điền MaxMind, Tencent Map hoặc ipapi credentials nếu cần</span></span>
<span class="line"><span>-&gt; Save settings</span></span>
<span class="line"><span>-&gt; Mở User Management</span></span>
<span class="line"><span>-&gt; Review IP source, address, total upload size và upload count</span></span>
<span class="line"><span>-&gt; Dùng search, sort hoặc advanced filters để tìm IPs bất thường</span></span>
<span class="line"><span>-&gt; Allow hoặc block uploads tùy tình huống</span></span></code></pre></div>`,64)])])}const x=l(p,[["render",h]]);export{P as __pageData,x as default};
